frappe.ui.form.on('Assignment Submission', {
    refresh: function(frm) {
        if (frm.doc.assignment && frm.doc.assignment_type) {
            frappe.call({
                method: 'frappe.client.get_value',
                args: {
                    doctype: frm.doc.assignment_type,
                    name: frm.doc.assignment,
                    fieldname: 'due_datetime'
                },
                callback: function(r) {
                    if (r.message && r.message.due_datetime) {
                        var due = moment(r.message.due_datetime);
                        var now = moment();
                        if (now.isAfter(due)) {
                            frm.page.add_menu_item('Submission Closed', function() {
                                frappe.msgprint('Past due date: ' + due.format('YYYY-MM-DD HH:mm'));
                            });
                            $('button.btn-primary-primary').prop('disabled', true).text('Past Due');
                        }
                    }
                }
            });
        }
    }
});

frappe.ui.form.on('Payment Entry', {
    party: function(frm) {
        if (!frm.doc.party) {
            frm.set_value('student_class', '');
            frm.set_value('student_section', '');
            frm.set_value('student_category', '');
            return;
        }
        frappe.db.get_value('Student',
            {'full_name': frm.doc.party},
            ['student_class', 'section', 'student_category'],
            function(student) {
                if (student) {
                    frm.set_value('student_class', student.student_class || '');
                    frm.set_value('student_section', student.section || '');
                    frm.set_value('student_category', student.student_category || '');
                }
            }
        );
    },
    fees_structure: function(frm) {
        if (!frm.doc.fees_structure) {
            frm.set_value('academic_year', '');
            frm.set_value('academic_term', '');
            return;
        }
        frappe.db.get_value('Fees Structure',
            frm.doc.fees_structure,
            ['year', 'term'],
            function(fs) {
                if (fs) {
                    frm.set_value('academic_year', fs.year || '');
                    frm.set_value('academic_term', fs.term || '');
                }
            }
        );
    }
});

frappe.ui.form.on('Student', {
    refresh: function(frm) {
        frm.set_query('section', function() {
            return { filters: frm.doc.student_class ? { student_class: frm.doc.student_class } : {} };
        });
        if (!frm.is_new()) {
            frm.set_df_property('has_opening_balance', 'read_only', 1);
            frm.set_df_property('opening_balance', 'read_only', 1);
            frm.set_df_property('opening_balance_date', 'read_only', 1);
        }

        // Override all attach image fields to not auto-save
        ['student_image', 'father_photo', 'mother_photo', 'guardian_photo'].for_each(function(fieldname) {
            var field = frm.get_field(fieldname);
            if (field && field.df) {
                field.on_upload_complete = function() {
                    frm.dirty();
                };
            }
        });
    }
});

