});

frappe.ui.form.on('Term Exam Result Item', {
    marks_obtained(frm, cdt, cdn) {
        calculate_grade(frm, cdt, cdn);
    },
    max_marks(frm, cdt, cdn) {
        calculate_grade(frm, cdt, cdn);
    },
    grading_score(frm, cdt, cdn) {
        calculate_grade(frm, cdt, cdn);
    },
    percentage(frm, cdt, cdn) {
        calculate_grade(frm, cdt, cdn);
    }
});

function calculate_grade(frm, cdt, cdn) {
    let row = locals[cdt][cdn];
    if (row.max_marks && row.marks_obtained != null) {
        let perc = (flt(row.marks_obtained) / flt(row.max_marks)) * 100;
        frappe.model.set_value(cdt, cdn, 'percentage', flt(perc, 2));

        if (row.grading_score) {
            frappe.db.get_doc('Grading Score', row.grading_score)
                .then(r => {
                    let items = r.message.grading_items || [];
                    let match = items.find(item => 
                        perc >= item.from_percent && 
                        (!item.to_percent || perc <= item.to_percent)
                    );
                    frappe.model.set_value(cdt, cdn, 'grade', match ? match.grade : '');
                });
        }
    }
    frm.refresh_field('term_exam_results');
}

frappe.ui.form.on('Receipting', {
    refresh: function(frm) {
        console.log("Receipting Script Loaded");
        frm.trigger('set_account_query');
    },

    set_account_query: function(frm) {
        frm.set_query('account', function() {
            return {
                filters: [
                    ['Account', 'account_type', 'in', ['Bank', 'Cash']],
                    ['Account', 'is_group', '=', 0]
                ]
            };
        });
    },

    payment_method: function(frm) {
        console.log("Payment Method Changed to: " + frm.doc.payment_method);
        if (frm.doc.payment_method) {
            let parent_acc = (frm.doc.payment_method === "Bank") ? "Bank Accounts - SS" : "Cash In Hand - SS";

            frappe.db.get_value('Account', {'parent_account': parent_acc, 'is_group': 0}, 'name', (r) => {
                if (r && r.name) {
                    console.log("Setting account to: " + r.name);
                    frm.set_value('account', r.name);
                }
            });
        }
    }
});

frappe.ui.form.on('Test Schedule', {
    test_name: function(frm) {
        if (frm.doc.test_name) {
            frappe.db.get_value('Inclass Test', frm.doc.test_name, ['max_marks_percent', 'min_marks_percent'], function(r) {
                if (r) {
                    frm.set_value('max_marks', r.max_marks_percent);
                    frm.set_value('min_marks', r.min_marks_percent);
                }
            });
        }
    },
    student_class: function(frm) {
        frm.clear_table('test_items');
        frm.refresh_field('test_items');
    },

    section: function(frm) {
        frm.clear_table('test_items');
        frm.refresh_field('test_items');
    },

    fetch_students: function(frm) {
        if (!frm.doc.student_class) {
            frappe.msgprint(__('Please select a Class first'));
            return;
        }

        let filters = {'student_class': frm.doc.student_class};
        if (frm.doc.section) {
            filters['section'] = frm.doc.section;
        }

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Student',
                filters: filters,
                fields: ['name', 'student_reg_no', 'full_name'],
                limit_page_length: 0,
                order_by: 'student_reg_no'
            },
            callback: function(r) {
                if (r.message && r.message.length > 0) {
                    frm.clear_table('test_items');
                    r.message.forEach(function(student) {
                        let row = frm.add_child('test_items');
                        row.student = student.name;
                        row.student_reg_no = student.student_reg_no;
                        row.student_name = student.full_name;
                    });
                    frm.refresh_field('test_items');
                    frappe.show_alert({
                        message: __('{0} students added', [r.message.length]),
                        indicator: 'green'
                    });
                } else {
                    frappe.msgprint(__('No students found'));
                }
            }
        });
    }
});

